// Phase 18e — workflow JSON shadow flags (no $env; staging n8n blocks env in expressions)
const inbound = $input.first().json;
return [{
  json: {
    ...inbound,
    shadow_mode: true,
    dry_run: true,
    live_send_enabled: false,
    live_send_blocked: true
  }
}];

// Phase 18e — parse inbound WhatsApp-style guest message for /staff/bot/guest-reply-draft
// Expected shape: { client_slug, from, guest_name, language, message_text, channel }
// No secrets extracted here. No DB writes. No WhatsApp send.

const body = $input.first().json.body || $input.first().json;

const clientSlug  = String(body.client_slug || 'wolfhouse-somo').trim();
const from        = String(body.from || body.phone || body.guest_phone || '').trim();
const guestName   = String(body.guest_name || body.name || '').trim() || null;
const language    = String(body.language || 'en').trim();
const messageText = String(body.message_text || body.text || body.message || '').trim();
const channel     = String(body.channel || 'whatsapp').trim();

if (!messageText) {
  throw new Error('Missing required field: message_text');
}

return [{
  json: {
    client_slug: clientSlug,
    from,
    phone: from,
    guest_name: guestName,
    language,
    message_text: messageText,
    channel,
    source: 'luna_whatsapp_shadow',
    shadow_mode: true,
    dry_run: true,
    live_send_enabled: false,
    live_send_blocked: true
  }
}];
